VALUES
  ('judicial-d35ec6db-moex-00307', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-3d2b73b6', 'sub-judicial-d35ec6db-07', NULL, 'single_choice', '下列何項情形，最符合「裁量怠惰」之描述？', '["行政機關裁量之結果，超出法律授權之範圍", "行政機關依法有裁量之權限，但因故意或過失而消極不行使裁量權", "行政機關作成裁量與法律授權之目的不符", "行政機關出於不相關之動機而作成裁量"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00308', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-3d2b73b6', 'sub-judicial-d35ec6db-07', NULL, 'single_choice', '關於行為人犯罪故意的判斷，依實務見解，下列敘述何者錯誤？', '["A誤熊為仇人B而開槍射擊，A有殺人故意", "A欲開槍射殺B卻誤中在旁的C，A對C沒有殺人故意", "A誤B為C而欲開槍射殺之，卻誤中在旁的D，A對B有殺人故意", "A誤將B的錢包當成自己錢包而取錢花用，A對B的錢包有竊盜故意"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00309', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-3d2b73b6', 'sub-judicial-d35ec6db-07', NULL, 'single_choice', '甲律師於看守所接見被告乙時，提供開鎖工具給在押的乙，乙因而成功脫逃。甲有何刑責？', '["甲構成刑法第161條的脫逃罪", "甲構成刑法第162條的縱放或便利脫逃罪", "甲構成刑法第163條的公務員縱放或便利脫逃罪", "甲不構成犯罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00310', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-3d2b73b6', 'sub-judicial-d35ec6db-07', NULL, 'single_choice', '關於著作財產權之利用，以下敘述何者正確？', '["著作財產權人得授權他人利用著作，其授權利用之內容與利用方法，依當事人之約定；其約定不明之部 分，推定為已授權", "著作財產權之授權，不因著作財產權人嗣後將其著作財產權讓與或再為授權而受影響", "專屬授權之被授權人在被授權範圍內，得以著作財產權人之地位行使權利，並得以自己名義為訴訟上之 行為。但不排除著作財產權人在專屬授權範圍內同時行使權利", "以著作財產權設質時，除另有約定，著作財產權人不得行使其著作財產權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00311', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-3d2b73b6', 'sub-judicial-d35ec6db-07', NULL, 'single_choice', '依勞動基準法第15條之1規定，雇主約定最低服務年限之合法性，應參考有無提供專業培訓、支付培訓 費用、提供補償等因素。下列何者非屬專業技術培訓？', '["旅行社教導新進員工公司最新的旅遊促銷方案", "航空公司選送培訓機師出國訓練", "理髮沙龍長期指導新進成員美髮技術跟知識", "工程公司指派勞工出國學習操作昂貴設備之認證課程"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00312', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-3d2b73b6', 'sub-judicial-d35ec6db-07', NULL, 'single_choice', '依地方制度法規定，下列何者不屬於設籍於臺東縣人民得享有之地方自治團體居民之權利？', '["選舉臺東縣立法委員", "使用臺東縣立文化中心", "就臺東縣自治事項提出創制案", "請求臺東縣政府公開政府資訊"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00313', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-3d2b73b6', 'sub-judicial-d35ec6db-07', NULL, 'single_choice', '有關行政程序法之聽證程序，下列敘述何者正確？', '["基於公正中立之考量，聽證之主持人不得由行政機關首長或其指定人員擔任", "行政機關為使聽證順利進行，認為必要時，得於聽證期日前，舉行預備聽證", "聽證應公開以言詞為之，但行政機關得於當事人同意時以書面為之", "當事人認為主持人於聽證程序進行中所為之處置違法或不當者，僅得於對實體決定聲明不服時一併聲明之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00314', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-3d2b73b6', 'sub-judicial-d35ec6db-07', NULL, 'single_choice', '下列何者是依民法規定僅適用於不動產的擔保物權？', '["地上權", "普通抵押權", "農育權", "不動產役權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00315', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-3d2b73b6', 'sub-judicial-d35ec6db-07', NULL, 'single_choice', '住在高雄之甲乙為夫妻，並育有8歲大的兒子丙。然甲因最近失業心情不好，常借酒澆愁，酒後更時常在 丙面前對乙暴力相向。試問依家庭暴力防治法之規定：乙若想向法院聲請民事保護令，應向下列那個法院 提出聲請？', '["臺灣臺北地方法院", "臺灣高雄地方法院", "臺灣高雄少年及家事法院", "臺灣橋頭地方法院"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00316', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-3d2b73b6', 'sub-judicial-d35ec6db-07', NULL, 'single_choice', '稱旅遊契約者，謂旅客與旅遊營業人所訂定之契約。關於旅客之權利，下列敘述何者錯誤？', '["旅遊營業人安排旅客在特定場所購物，其所購物品有瑕疵者，旅客得於受領所購物品後一個月內，請求 旅遊營業人協助其處理", "旅遊營業人隨時得變更旅遊內容", "旅客在旅遊中發生身體或財產上之事故時，旅客得請求旅遊營業人為必要之協助及處理", "旅遊未完成前，旅客得隨時終止契約，但應賠償營業人因契約終止而生之損害"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL)
